SELECT hashtag_name, popularity_score
FROM hashtags
ORDER BY popularity_score DESC;

SELECT platform, location, AVG(sentiment_score) AS avg_sentiment_score
FROM posts
GROUP BY platform, location;

SELECT p.post_id, p.original_text, p.sentiment_score
FROM posts p
WHERE p.sentiment_score > (
    SELECT AVG(sentiment_score) 
    FROM posts
);

SELECT *
FROM posts
ORDER BY sentiment_score DESC;
